import { Actions } from '@app/actions/shared';
import {
  isMessageOfType,
  SubscriptionExpiringToastClickedStatus,
  SubscriptionExpiringToastStatus,
} from '@app/messages/shared';
import { browser_api } from '@app/browser_api';
import { showToast } from '@content/components/customToast';
import i18n from '@content/i18n';
import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { messageDispatcher } from '@app/infrastructure/messageDispatcher';

const initSubscriptionExpiringOnYoutubePageListener = async (
  message: unknown,
): Promise<void> => {
  if (isMessageOfType(message, Actions.ShowSubscriptionExpiringToast)) {
    showSubscriptionExpiringToastOnPage(message.payload.status);
  }
};

export async function initSubscriptionExpiringOnYoutubePage(): Promise<void> {
  try {
    if (
      !browser_api.runtime.onMessage.hasListener(
        initSubscriptionExpiringOnYoutubePageListener,
      )
    ) {
      browser_api.runtime.onMessage.addListener(
        initSubscriptionExpiringOnYoutubePageListener,
      );
    }

    await messageDispatcher.send({
      action: Actions.InitSubscriptionExpiringScriptReady,
    });
  } catch (error) {
    console.error(error);
  }
}

async function showSubscriptionExpiringToastOnPage(
  status: SubscriptionExpiringToastStatus,
) {
  try {
    const { peremenSubscriptionNotificationBlocked } =
      await getLocalStorageData(
        LocalStorageKey.PeremenSubscriptionNotificationBlocked,
      );

    if (peremenSubscriptionNotificationBlocked) return;

    showToast({
      title:
        status === 'expiring'
          ? i18n.t('content:toast.subscriptionExpiring.titleExpiring')
          : i18n.t('content:toast.subscriptionExpiring.titleExpired'),
      text: i18n.t('content:toast.subscriptionExpiring.text'),
      buttons: [
        {
          text: i18n.t('content:toast.subscriptionExpiring.buyButton'),
          onClick: async () => {
            await handleSubscriptionExpiringToastClick('buy-subscription');
          },
          accent: true,
        },
        {
          text: i18n.t('content:toast.subscriptionExpiring.goToFreeButton'),

          onClick: async () => {
            await handleSubscriptionExpiringToastClick('go-to-free');
          },
        },
      ],
      type: 'subscriptionExpiring',
      closeBehavior: 'allInAllTabsByType',
    });
  } catch (error) {
    console.error('Error on showing subscription expiring toast', error);
  }
}

async function handleSubscriptionExpiringToastClick(
  status: SubscriptionExpiringToastClickedStatus,
): Promise<void> {
  try {
    await messageDispatcher.send({
      action: Actions.SubscriptionExpiringToastClicked,
      payload: { status },
    });
  } catch (error) {
    console.error('Error handling subscription expiring toast click:', error);
  }
}
