import i18n from 'i18next';
import { initReactI18next } from 'react-i18next';
import { InitI18nOptions, SupportedLanguages } from './types';
import {
  getI18nConfig,
  syncLanguageToStorage,
  getDefaultLocale,
} from './utils';

export type { SupportedLanguages } from './types';

let isInitialized = false;

export async function initI18n(options: InitI18nOptions): Promise<typeof i18n> {
  if (isInitialized) {
    return i18n;
  }

  i18n.on('languageChanged', (language) => {
    if (!supportedLngs.includes(language as SupportedLanguages)) return;
    void syncLanguageToStorage(language);
    void onLanguageChanged(language);
  });

  const {
    enableReact = false,
    debug = false,
    onLanguageChanged,
    context,
  } = options;

  const { supportedLngs, resources } = await getI18nConfig(context);
  const defaultLocale = await getDefaultLocale(supportedLngs, context);

  if (enableReact) {
    i18n.use(initReactI18next);
  }

  i18n.init({
    lng: defaultLocale,
    supportedLngs,
    fallbackLng: supportedLngs,
    debug,
    defaultNS: 'shared',
    resources,
  });

  isInitialized = true;
  return i18n;
}

export default i18n;
