import { getLocalStorageData } from '@app/storage/local/shared';

import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { logger } from '@utils/logger';

export const getConfigsUrl = async (endpoint?: string) => {
  if (!endpoint) {
    logger.error('getConfigsUrl: No endpoint provided');

    return null;
  }
  const { configsBaseUrl } = await getLocalStorageData(
    LocalStorageKey.ConfigsBaseUrl,
  );

  if (configsBaseUrl) {
    return new URL(endpoint, configsBaseUrl);
  }
  return new URL(endpoint, process.env.CONFIG_BASE_URL_1);
};
